impl<R: PasswordResetSecurityProjectionRepository> PasswordResetSecurityEventHandler for PasswordResetSecurityProjector<R> {

    async fn on_created(&self, event: PasswordResetSecurityCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = PasswordResetSecurityProjection::new(
            event.id,
            event.max_attempts,
            event.attempts_remaining,
            event.last_attempt_at,
            event.expires_at,
            event.suspicious_activity,
            event.risk_score,
            event.security_flags,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: PasswordResetSecurityUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.max_attempts = event.max_attempts;
            projection.attempts_remaining = event.attempts_remaining;
            projection.last_attempt_at = event.last_attempt_at;
            projection.expires_at = event.expires_at;
            projection.suspicious_activity = event.suspicious_activity;
            projection.risk_score = event.risk_score;
            projection.security_flags = event.security_flags;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: PasswordResetSecurityDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

